import subprocess
# Use dotnet to decompile and list Assert methods
result = subprocess.run(
    ['dotnet', 'build', '--no-restore', '-getProperty:TargetFramework'],
    capture_output=True, text=True,
    cwd='/tmp/sv-dbabc6a6b52947f29a16aa812dbd1619'
)

# Let's use reflection via a simple C# script to check Assert API
script = '''
using System;
using System.Reflection;
using System.Linq;

var asm = Assembly.LoadFrom("/home/runner/.nuget/packages/mstest.testframework/4.2.2/lib/net8.0/MSTest.TestFramework.dll");
var assertType = asm.GetTypes().FirstOrDefault(t => t.Name == "Assert");
if (assertType != null) {
    var methods = assertType.GetMethods(BindingFlags.Public | BindingFlags.Static)
        .Where(m => m.Name == "AreEqual" || m.Name == "AreNotEqual" || m.Name == "AreSame")
        .OrderBy(m => m.Name);
    foreach (var m in methods) {
        var parms = string.Join(", ", m.GetParameters().Select(p => p.ParameterType.ToString() + " " + p.Name));
        var genArgs = m.IsGenericMethod ? "<" + string.Join(",", m.GetGenericArguments().Select(a => a.Name)) + ">" : "";
        Console.WriteLine($"{m.Name}{genArgs}({parms})");
    }
} else {
    Console.WriteLine("Assert type not found");
    foreach (var t in asm.GetTypes().Take(20))
        Console.WriteLine(t.FullName);
}
'''

with open('/tmp/check_assert.csx', 'w') as f:
    f.write(script)

result = subprocess.run(['dotnet', 'script', '/tmp/check_assert.csx'], capture_output=True, text=True)
print("STDOUT:", result.stdout)
print("STDERR:", result.stderr[:500])
EOF

