        .Where(m => m.Name == "AreEqual" || m.Name == "AreNotEqual" || m.Name == "AreSame")
        .OrderBy(m => m.Name);
    foreach (var m in methods) {
        var parms = string.Join(", ", m.GetParameters().Select(p => p.ParameterType.ToString() + " " + p.Name));
        var genArgs = m.IsGenericMethod ? "<" + string.Join(",", m.GetGenericArguments().Select(a => a.Name)) + ">" : "";
        Console.WriteLine($"{m.Name}{genArgs}({parms})");
    }
} else {
    Console.WriteLine("Assert type not found");
}
